import bisect
class Solution:
    def minWastedSpace(self, packages, boxes):
        MOD = 10 ** 9 + 7
        packages.sort()
        n = len(packages)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + packages[i]
        total = pre[n]
        best = float('inf')
        for supplier in boxes:
            bs = sorted(supplier)
            if bs[-1] < packages[-1]:
                continue
            used = 0
            prev = 0
            for b in bs:
                hi = bisect.bisect_right(packages, b)
                used += b * (hi - prev) - (pre[hi] - pre[prev])
                prev = hi
                if prev == n:
                    break
            if used < best:
                best = used
        if best == float('inf'):
            return -1
        return best % MOD

