var minWastedSpace = function(packages, boxes) {
    const MOD = 1000000007n;
    packages.sort((a, b) => a - b);
    const n = packages.length;
    const pre = new Array(n + 1).fill(0n);
    for (let i = 0; i < n; i++) pre[i + 1] = pre[i] + BigInt(packages[i]);
    const maxPkg = packages[n - 1];
    const upperBound = (x) => {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (packages[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    let best = null;
    for (const supplier of boxes) {
        const bs = supplier.slice().sort((a, b) => a - b);
        if (bs[bs.length - 1] < maxPkg) continue;
        let used = 0n;
        let prev = 0;
        for (const b of bs) {
            const hi = upperBound(b);
            used += BigInt(b) * BigInt(hi - prev) - (pre[hi] - pre[prev]);
            prev = hi;
            if (prev === n) break;
        }
        if (best === null || used < best) best = used;
    }
    if (best === null) return -1;
    return Number(((best % MOD) + MOD) % MOD);
};
